#!/usr/bin/env python3
import os,sys,json,time,subprocess
def sh(c,t=20):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
out={"kind":"srcscope","ts":int(time.time())}
try:
    out["discovery_units"]=sh("systemctl list-unit-files --no-legend 2>/dev/null | awk '{print $1}' | grep -iE 'discover|source|promote|socrata'")
    out["discovery_timers"]=sh("systemctl list-timers --all --no-legend 2>/dev/null | grep -iE 'discover|source|promote' | awk '{print $5,$NF}'")
    out["disc_status"]=sh("systemctl is-active atlas-source-discovery.service 2>/dev/null; systemctl is-enabled atlas-source-discovery.timer 2>/dev/null")
    out["disc_recent"]=sh("journalctl -u atlas-source-discovery.service -n 6 --no-pager 2>&1 | tail -6")
    out["disc_code"]=sh("grep -nE 'catalog|api.us.socrata|search|discover|INSERT INTO|known|seed' /opt/atlas/importers/atlas_source_discovery.py 2>/dev/null | head -15")
    # definitive freshness kill
    fu=sh("systemctl list-units --all --no-legend --plain 2>/dev/null | awk '{print $1}' | grep -i fresh")
    out["fresh_units_all"]=fu
    for u in set(fu.split()):
        if u.strip(): sh("systemctl stop %s 2>/dev/null; systemctl disable %s 2>/dev/null; systemctl mask %s 2>/dev/null; systemctl reset-failed %s 2>/dev/null"%(u,u,u,u))
    out["fresh_after"]=sh("systemctl list-units --all --no-legend --plain 2>/dev/null | awk '$4==\"auto-restart\"{print $1}'")
except Exception as e: out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/srcscope.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"srcscope","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
